import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"G09 客戶供應商 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G09_客戶供應商.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G09_客戶供應商.md"}'),r={name:"審計報告庫/經營審計/6239_力成/20260617/G09_客戶供應商.md"};function i(s,t,d,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="g09-客戶供應商-—-力成科技-6239" tabindex="-1">G09 客戶供應商 — 力成科技 (6239) <a class="header-anchor" href="#g09-客戶供應商-—-力成科技-6239" aria-label="Permalink to &quot;G09 客戶供應商 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>評估力成科技的客戶與供應商結構，包含集中度、議價能力、合作關係穩定性及產業鏈地位。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>前三大客戶（金士頓、美光、鎧俠）佔營收55-60%，集中度偏高但均為長期夥伴。供應端日系設備依賴度高，本土採購率85%可部分緩解。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>前三大客戶金士頓（25-30%）、美光（20-25%）、鎧俠（10-15%）合佔55-60%，集中度中度偏高但均為長期夥伴。設備材料以日系為主（Advantest/Disco/味之素），本土採購率85%。客戶綁定度高，集中風險存在。評級中上。（數據來源：CMoney、YouTube商業分析）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技的供應鏈生態系統分析：</p><p><strong>一、主要客戶深度分析</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">客戶</th><th style="text-align:left;">關係</th><th style="text-align:left;">佔比</th><th style="text-align:left;">穩定性</th></tr></thead><tbody><tr><td style="text-align:left;">金士頓</td><td style="text-align:left;">最大股東（~20%）、蔡篤恭任董座時為金士頓遠東區總經理</td><td style="text-align:left;">25-30%</td><td style="text-align:left;">極高，近30年合作</td></tr><tr><td style="text-align:left;">美光</td><td style="text-align:left;">五年LTA、保障50% DRAM封測產能</td><td style="text-align:left;">20-25%</td><td style="text-align:left;">高，但2024收回西安廠</td></tr><tr><td style="text-align:left;">鎧俠（東芝記憶體）</td><td style="text-align:left;">NAND封測長期合作、法人代表入董事會</td><td style="text-align:left;">10-15%</td><td style="text-align:left;">高</td></tr><tr><td style="text-align:left;">NVIDIA</td><td style="text-align:left;">AI晶片封測、亞利桑那廠獨家供應商</td><td style="text-align:left;">5-10%</td><td style="text-align:left;">成長中</td></tr><tr><td style="text-align:left;">Bosch/Continental/電裝</td><td style="text-align:left;">車用模組（日本秋田廠）</td><td style="text-align:left;">5-8%</td><td style="text-align:left;">高</td></tr></tbody></table><p><strong>二、供應商結構</strong> 關鍵設備與材料對日系供應商依賴度高。測試機台以Advantest（日本）和Teradyne（美國）為主，封裝設備以Disco（日本切割機）、Towa（日本封膠機）為核心。封裝材料方面，基板主要向欣興、景碩、南亞電路板等台廠採購；導線架向長華科、順德等台廠採購；封裝膠向住友電木、味之素（日系）採購。</p><p><strong>三、供應鏈合作模式</strong> 力成與供應商建立深度合作：參與設備商的下一代機台開發測試、優先取得產能分配；與材料供應商合作開發專用材料（如FOPLP專用膠材）；要求供應商2026年前減碳20%，建構綠色供應鏈。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>客戶集中度形成議價壓力</strong>：金士頓為最大股東兼客戶，雖然穩定性高，但大股東雙重角色可能使力成在報價談判中處於被動。當記憶體產業進入下行週期時，客戶可能強烈要求降價以維持自身獲利。</li><li><strong>美光垂直整合的警訊</strong>：2024年美光收回力成西安廠自行營運，顯示記憶體大廠有自建封測產能的意願與能力。雖然目前五年LTA保障產能，但長期來看，若美光進一步擴大自製封測比例，力成將面臨結構性的訂單侵蝕風險。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>客戶關係嵌入形成高壁壘</strong>：力成為金士頓封測服務近30年，為美光封測服務超過15年。這種長時間的技術磨合、製程認證與產能規劃合作，形成了極高的轉換成本——更換封測廠需要重新認證數百個產品型號，耗時1-2年，大客戶幾乎不可能輕易轉換。</li><li><strong>NVIDIA等AI客戶拓展分散集中度</strong>：NVIDIA指定力成美國廠為獨家供應商，AI晶片客戶佔比從2024年不到5%提升至2026年Q1超過10%。新客戶的持續加入正逐步稀釋對金士頓/美光的過度依賴，客戶結構趨向多元化。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：力成 6239 行銷通路 客戶 供應商 集中度（CMoney分析）</li><li>web_search：力成 6239 法說會（Fugle備忘錄2026/04/28）</li><li>tavily_search：力成 6239 商業模式（YouTube深度分析）</li><li>經濟日報：力成法說會報導2025/12/27</li></ul>',20)])])}const x=e(r,[["render",i]]);export{_ as __pageData,x as default};
